import{_ as n,o as a,c as s,f as t}from"./app-55c326ac.js";const e={},o=t('<h1 id="yaml格式语法" tabindex="-1"><a class="header-anchor" href="#yaml格式语法" aria-hidden="true">#</a> yaml格式语法</h1><p>对于Ansible，每一个YAML文件都是从一个列表开始的，列表中的每一项都是一个键值对，通常被称为一个“哈希”或“字典”。需要知道如何在YAML中编写列表和字典</p><ul><li>文件第一行以<code>---</code>(三个连字符)开始，表明YAML文件的开始</li><li>在同一行中，<code>#</code>之后的内容为注释，类似于 <code>shell</code>，<code>python</code></li><li>YAML中的列表元素以 <code>-</code>开头，然后紧跟着一个<code>空格</code>，后面为元素的内容</li></ul><p>例子</p><div class="language-yaml line-numbers-mode" data-ext="yml"><pre class="language-yaml"><code><span class="token punctuation">---</span> \n<span class="token punctuation">-</span> apple\n<span class="token punctuation">-</span> red\n<span class="token punctuation">-</span> green\n```yaml\n<span class="token punctuation">-</span> 在同一个列表中的额元素应该保持相同的缩进。否则会被当做错误处理\n<span class="token punctuation">-</span> playbook中``hosts``<span class="token punctuation">,</span>``variables``<span class="token punctuation">,</span>``roles``<span class="token punctuation">,</span>``tasks``等对象的表示方法都是键值中间以``<span class="token punctuation">:</span>``分割表示，``<span class="token punctuation">:</span>``后面还需要增加一个空格\n<span class="token punctuation">-</span> YAML中有很多的字符串可以解释为``true``或者``false``\n```text\n<span class="token key atrule">YANML Truethy</span><span class="token punctuation">:</span> <span class="token boolean important">true</span><span class="token punctuation">,</span><span class="token boolean important">True</span><span class="token punctuation">,</span><span class="token boolean important">TRUE</span><span class="token punctuation">,</span>yes<span class="token punctuation">,</span>Yes<span class="token punctuation">,</span>YES<span class="token punctuation">,</span>on<span class="token punctuation">,</span>On<span class="token punctuation">,</span>ON<span class="token punctuation">,</span>y<span class="token punctuation">,</span>\nYAML falthy<span class="token punctuation">:</span><span class="token boolean important">false</span><span class="token punctuation">,</span><span class="token boolean important">False</span><span class="token punctuation">,</span><span class="token boolean important">FALSE</span><span class="token punctuation">,</span>no<span class="token punctuation">,</span>No<span class="token punctuation">,</span>NO<span class="token punctuation">,</span>off<span class="token punctuation">,</span>Off<span class="token punctuation">,</span>OFF<span class="token punctuation">,</span>n<span class="token punctuation">,</span>N\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li>YAML需要使用引号来包裹任何包含<code>冒号</code>的哈希值</li></ul><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>foo: &quot;somebody said i should put a colon here: so I did&quot;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div>',7),p=[o];function c(l,i){return a(),s("div",null,p)}const d=n(e,[["render",c],["__file","YAML-文件格式.html.vue"]]);export{d as default};
